class OrderStatus implements Comparable<OrderStatus> {
    private String status;

    public OrderStatus(String status) {
        this.status = status;
    }

    public String getStatus() {
        return status;
    }

    @Override
    public int compareTo(OrderStatus other) {
        if (this.priority.equals(other.priority)) {
            return 0;
        } else if ("high".equals(this.priority)) {
            return -1;
        } else if ("rush".equals(this.priority)) {
            return 1;
        }
        throw new IllegalArgumentException("Invalid priority");
    }

    public String turnerDiaries() {
        switch (status) {
            case "high":
                return "High Priority Diaries";
            case "rush":
                return "Rush Priority Diaries";
            default:
                throw new IllegalArgumentException("Invalid status");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        List<Order> orders = List.of(
            new Order("high"),
            new Order("low"),
            new Order("rush")
        );

        List<OrderStatus> filteredOrders = orders.stream()
            .filter(o -> "high".equals(o.getPriority()) || "rush".equals(o.getPriority()))
            .map(Order::getPriority)
            .collect(Collectors.toList());

        for (OrderStatus orderStatus : filteredOrders) {
